import axios from 'axios';

// Replace this with your actual Figma file ID
const FILE_ID = 'NBHU5lsSfPTBMnlFVPxHNB'; // Figma file ID from the URL
const FIGMA_TOKEN = 'figd_9IgwTEDRk2P6kWhTjRvtOmkFcAKniW9pPya9ohwA'; // Your Figma personal access token

// The base URL for Figma API
const FIGMA_API_URL = 'https://api.figma.com/v1';

/**
 * Fetch all components from the Figma file
 * @returns {Promise<Array>} - List of components from Figma
 */
export const fetchFigmaComponents = async () => {
    try {
      // Send a GET request to the Figma API to retrieve the file data
      const response = await axios.get(`${BASE_URL}/files/${FILE_ID}`, {
        headers: {
          'X-Figma-Token': FIGMA_TOKEN,  // Authentication token
        },
      });

      // Extract the components from the Figma file data
      const components = response.data.document.children[0].children.filter(
        (node) => node.type === 'COMPONENT' || node.type === 'INSTANCE'
      );

      // Log and return the components
      console.log('Fetched Components:', components);
      return components;
    } catch (error) {
      console.error('Error fetching components from Figma:', error);
      throw error; // Optionally handle the error in the calling function
    }
  };
